import {
  addDoc,
  collection,
  doc,
  onSnapshot,
  serverTimestamp,
  type Unsubscribe,
} from "firebase/firestore";

import { auth, db } from "@/lib/firebase/client";

type ExtensionCheckoutResult = {
  sessionId?: string;
  url?: string;
};

type PortalResult = {
  url?: string;
};

async function authorizedPost(path: string, body?: Record<string, string>) {
  const user = auth.currentUser;

  if (!user) {
    throw new Error("You must be signed in.");
  }

  const token = await user.getIdToken();

  const response = await fetch(path, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      authorization: `Bearer ${token}`,
    },
    body: JSON.stringify(body ?? {}),
  });

  if (!response.ok) {
    const payload = (await response.json().catch(() => ({}))) as { error?: string };
    throw new Error(payload.error ?? "Request failed.");
  }

  return (await response.json()) as PortalResult;
}

export async function createCheckoutSession(priceId?: string): Promise<ExtensionCheckoutResult> {
  const user = auth.currentUser;

  if (!user) {
    throw new Error("You must be signed in.");
  }

  if (!priceId) {
    throw new Error("Missing Stripe price ID.");
  }

  const baseUrl = process.env.NEXT_PUBLIC_APP_URL ?? window.location.origin;
  const customerRef = doc(db, "customers", user.uid);
  const checkoutSessionsRef = collection(customerRef, "checkout_sessions");

  const checkoutSessionDoc = await addDoc(checkoutSessionsRef, {
    price: priceId,
    mode: "subscription",
    success_url: `${baseUrl}/checkout/return?session_id={CHECKOUT_SESSION_ID}`,
    cancel_url: `${baseUrl}/pricing`,
    allow_promotion_codes: true,
    createdAt: serverTimestamp(),
  });

  return new Promise<ExtensionCheckoutResult>((resolve, reject) => {
    let unsubscribe: Unsubscribe | null = null;

    unsubscribe = onSnapshot(
      checkoutSessionDoc,
      (snapshot) => {
        const data = snapshot.data() as {
          sessionId?: string;
          url?: string;
          error?: { message?: string } | string;
        } | undefined;

        if (!data) {
          return;
        }

        if (data.error) {
          if (unsubscribe) unsubscribe();
          const message =
            typeof data.error === "string"
              ? data.error
              : data.error.message ?? "Failed to create Stripe checkout session.";
          reject(new Error(message));
          return;
        }

        if (data.url || data.sessionId) {
          if (unsubscribe) unsubscribe();
          resolve({
            url: data.url,
            sessionId: data.sessionId,
          });
        }
      },
      (error) => {
        if (unsubscribe) unsubscribe();
        reject(error);
      },
    );
  });
}

export async function createBillingPortalSession() {
  return authorizedPost("/api/stripe/portal");
}
